import{_ as e,p as l,q as i,a1 as a}from"./framework-e0dd9823.js";const r={},t=a('<h1 id="基本句型" tabindex="-1"><a class="header-anchor" href="#基本句型" aria-hidden="true">#</a> 基本句型</h1><p>英语中主要有五种基本句型，分为两大类：前四个为主谓宾类型，表示动作。第五个是主系表，表示状态</p><ol><li>主语 + 谓语(不及物动词) + 状语</li></ol><ul><li>I work every day 我每天工作</li><li>I run every day 我每天跑步</li><li>I live in Xi&#39;an city 我住在西安市</li></ul><ol start="2"><li>主语 + 谓语(及物动词) + 宾语 + 状语</li></ol><ul><li>I read English every day 我每天读英语</li><li>We bake beef every mouth 我们每个月考牛肉</li><li>She learns English every day 她努力学习英语</li></ul><ol start="3"><li>主语 + 谓语(双宾动词) + 双宾语 + 谓语</li></ol><ul><li>I gave her a book yesterday 我昨天给她一本书</li><li>They sent me a computer last week 上周，他们送我一台电脑</li></ul><ol start="4"><li>主语 + 谓语(少数特定及物动词) + 宾语 + 宾补 + 状语</li></ol><ul><li>I made her happy yesterday 昨天，我让他开心</li><li>Her father called her Baby Bear before 她爸爸以前叫她“宝贝小熊”</li></ul><ol start="5"><li>主语 + be(系动词) + 标语 + 状语</li></ol><ul><li>She is rich now 她现在很富有</li><li>I am in Xi&#39;an now 我现在在西安</li><li>I was a worker before 我以前是一个工人</li></ul>',12),o=[t];function s(n,c){return l(),i("div",null,o)}const d=e(r,[["render",s],["__file","grammar-basic-patterns.html.vue"]]);export{d as default};
